from dataclasses import dataclass, field
from typing import Optional
from enum import Enum

class DPIAOutcome(str, Enum):
    APPROVED = "approved"
    APPROVED_WITH_CONDITIONS = "approved_with_conditions"
    SA_CONSULTATION_REQUIRED = "sa_consultation_required"

@dataclass
class DPIARecord:
    dpia_id: str
    feature_name: str
    feature_version: str
    completed_by: str
    completed_date: str
    dpo_name: str
    dpo_sign_off_date: Optional[str] = None
    outcome: Optional[DPIAOutcome] = None
    conditions: list[str] = field(default_factory=list)
    review_due_date: Optional[str] = None
    sa_consultation_date: Optional[str] = None
    risks: list = field(default_factory=list)    # list[DPIARisk]

    def has_high_residual_risk(self) -> bool:
        return any(
            r.requires_sa_consultation()
            for r in self.risks
            if hasattr(r, 'requires_sa_consultation')
        )

    def required_outcome(self) -> DPIAOutcome:
        if self.has_high_residual_risk():
            return DPIAOutcome.SA_CONSULTATION_REQUIRED
        if self.conditions:
            return DPIAOutcome.APPROVED_WITH_CONDITIONS
        return DPIAOutcome.APPROVED

    def is_go_live_approved(self) -> bool:
        return (
            self.outcome in (DPIAOutcome.APPROVED, DPIAOutcome.APPROVED_WITH_CONDITIONS) and
            self.dpo_sign_off_date is not None
        )

    def summary(self) -> str:
        return (
            f"DPIA {self.dpia_id} | {self.feature_name} v{self.feature_version} | "
            f"Outcome: {self.outcome.value if self.outcome else 'pending'} | "
            f"DPO sign-off: {self.dpo_sign_off_date or 'not yet'} | "
            f"Go-live approved: {self.is_go_live_approved()}"
        )
